import{_ as n,c as a,a as e,o as i}from"./app-CEcM0piI.js";const l={};function d(p,s){return i(),a("div",null,s[0]||(s[0]=[e(`<h2 id="索引签名" tabindex="-1"><a class="header-anchor" href="#索引签名"><span>索引签名</span></a></h2><p>用于限制键值对的类型</p><p>语法：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>{[key: keyType]: ValueType }</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>interface Dictionary {</span></span>
<span class="line"><span>	[key: boolean]: string;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="模板字面量类型" tabindex="-1"><a class="header-anchor" href="#模板字面量类型"><span>模板字面量类型</span></a></h3><p>配合索引签名使用限制参数的命名</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>interface PropchangeHandler {</span></span>
<span class="line"><span>	[key:\`\${istring}changed\`]:()=&gt; void;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Let handlers: PropchangeHandler={</span></span>
<span class="line"><span>	idChanged:()=&gt;{},    //ok</span></span>
<span class="line"><span>	nameChanged:()=&gt;{},    //ok</span></span>
<span class="line"><span>	agechange:()=&gt;{}    //err</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>索引签名参数类型不能为字面量类型或泛型类型。</strong> 索引签名定义键的类型只能是基础类型和模板字面量类型 record工具类定义键的类型可以是字面量类型以及字面量类型的联合类型</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>type User1={</span></span>
<span class="line"><span>	[key:&quot;id&#39;]: string;    //err</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>type User2={</span></span>
<span class="line"><span>	[key: &quot;id&quot; | &quot;name&quot;]: string;    //err</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>type User3 = Record&lt;&quot;id&quot;, string&gt;;    //ok</span></span>
<span class="line"><span>type User4 = Record&lt;&#39;id&#39; &quot;name&quot;,string&gt;;    //ok</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="映射类型" tabindex="-1"><a class="header-anchor" href="#映射类型"><span>映射类型</span></a></h2><p>将一个类型映射到当前类型，可在当前类型中修改修饰，可选属性等而不影响原类型，减少代码量 使用+或-前缀来添加或减少修饰符 如果没有前缀的话默认使用+</p><p>语法： P：新的映射类型 K：被映射的旧类型 in：类似foreach T：任意类型</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>{[P in K]:T}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>{[P in K]?:T}    //将K中的成员全部映射到P中并在P中将这些成员全部设为可选参数</span></span>
<span class="line"><span>{[P in K]-?:T}    //将K中的成员全部映射到P中并在P中将这些成员全部去除可选参数</span></span>
<span class="line"><span>{readonly[P in K]:T}    //将K中的成员全部映射到P中并在P中将这些成员全部添加readonly修饰符</span></span>
<span class="line"><span>{-readonly[P in K]:T}    //将K中的成员全部映射到P中并在P中将这些成员全部去除readonly修饰符</span></span>
<span class="line"><span>{readonly[P in K]-?:T}    ////将K中的成员全部映射到P中并在P中将这些成员全部添加readonly修饰符并全部去除可选参数</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="条件类型" tabindex="-1"><a class="header-anchor" href="#条件类型"><span>条件类型</span></a></h2><p>类型判定也可以使用三目运算符</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>T extends U ? X : Y</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>如果U包含T那么返回X，否则返回Y 大写字母都是类型占位符</p><p>extends判断是宽窄类型，并不局限于继承 如<code>string | number</code>和<code>string</code>就是宽类型包含窄类型，也可以判断成功</p><h1 id="关键字" tabindex="-1"><a class="header-anchor" href="#关键字"><span>关键字</span></a></h1><h2 id="record" tabindex="-1"><a class="header-anchor" href="#record"><span>Record</span></a></h2><p>除了索引签名也可以使用record简化键值对的限制</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>type Record &lt;k extends keyof any,T&gt; ={</span></span>
<span class="line"><span>	 [P in K]: T;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function calculateSalary(salaryObject:Record&lt;string,number&gt;){</span></span>
<span class="line"><span>	let total=0;</span></span>
<span class="line"><span>	for(const name in salaryObject){</span></span>
<span class="line"><span>		total += salaryObject[name];</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	return total;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="keyof" tabindex="-1"><a class="header-anchor" href="#keyof"><span>keyof</span></a></h2><p>获取到对象内部所有成员组成的联合类型</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function getAttribute&lt;T,D extends keyof T&gt;(obj: T, key: D): T[D] {</span></span>
<span class="line"><span>	return obj[key];</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>const user ={name:&#39;后盾人&#39;,age:18 }</span></span>
<span class="line"><span>getAttribute(user,&#39;name&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="readonly" tabindex="-1"><a class="header-anchor" href="#readonly"><span>readonly</span></a></h2><p>只读修饰符</p><h2 id="type类型别名" tabindex="-1"><a class="header-anchor" href="#type类型别名"><span>type类型别名</span></a></h2><p>类型别名type将一个类型命名一个别名 type和interface的区别</p><p><strong>使用类型别名的场景:</strong></p><ul><li>定义基本类型的别名时，使用 type</li><li>定义元组类型时，使用 type</li><li>定义函数类型时，使用 type</li><li>定义联合类型时，使用 type</li><li>定义映射类型时，使用 type <strong>使用接口的场景:</strong></li><li>需要利用接口自动合并特性的时候，使用 interface</li><li>定义对象类型且无需使用 type 的时候，使用 interface</li></ul><h3 id="interface可以类型合并-type不可以" tabindex="-1"><a class="header-anchor" href="#interface可以类型合并-type不可以"><span>interface可以类型合并，type不可以</span></a></h3><p><strong>interface</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>interface User {</span></span>
<span class="line"><span>	name: string;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>interface User {</span></span>
<span class="line"><span>	id: number;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let user:User{</span></span>
<span class="line"><span>	id:666,</span></span>
<span class="line"><span>	name:&#39;tom&#39;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>type</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>type User={</span></span>
<span class="line"><span>	name: string;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// err：标识符“User”重复</span></span>
<span class="line"><span>type User={</span></span>
<span class="line"><span>	id:number;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="类型别名可以为基本类型-联合类型或元组类型定义别名接口不行" tabindex="-1"><a class="header-anchor" href="#类型别名可以为基本类型-联合类型或元组类型定义别名接口不行"><span>类型别名可以为基本类型，联合类型或元组类型定义别名接口不行</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>type MvNumber = number;</span></span>
<span class="line"><span>type StringOrNumber = string | number;</span></span>
<span class="line"><span>type Point=[number,number];</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="模板字面量类型-1" tabindex="-1"><a class="header-anchor" href="#模板字面量类型-1"><span>模板字面量类型</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>type Direction = &quot;left&quot; | &quot;right&quot; | &quot;top&quot; | &quot;bottom&#39;&quot;;</span></span>
<span class="line"><span>type CssPadding =\`padding-\${Direction}\`;</span></span>
<span class="line"><span>type MarginPadding = \`margin-\${Direction}\`;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>多个占位符的联合类型解析为叉积</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>S1=A|B</span></span>
<span class="line"><span>S2=C|D</span></span>
<span class="line"><span></span></span>
<span class="line"><span>\`\${S1}-\${S2}\`=\`\${A}-\${C}\` | \`\${A}-\${D}\` | \`\${B}-\${C)\` | \`\${B}-\${D}\`</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="declare类型声明" tabindex="-1"><a class="header-anchor" href="#declare类型声明"><span>declare类型声明</span></a></h2><p>declare类型声明，在d.ts中使用，用于声明一个类型让ts编译器识别</p><ul><li>declare：声明</li><li>wx：全局变量名称</li><li>any：变量类型</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>declare var wx: any;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="类型兼容性" tabindex="-1"><a class="header-anchor" href="#类型兼容性"><span>类型兼容性</span></a></h2><p><strong>两种类型系统</strong>：</p><ol><li>StructuralTypeSystem（结构化类型系统）</li><li>NominalTypeSystem（标明类型系统）。</li></ol><p>TS 采用的是结构化类型系统，也叫做ducktyping（鸭子类型），类型检查关注的是值所具有的形状。 也就是说，在结构类型系统中，如果两个对象具有相同的形状，则认为它们属于同一类型。</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>class point{</span></span>
<span class="line"><span>	x:number,</span></span>
<span class="line"><span>	y:number</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>class point2D{</span></span>
<span class="line"><span>	x:number,</span></span>
<span class="line"><span>	y:number</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>class point3D{</span></span>
<span class="line"><span>	x:number,</span></span>
<span class="line"><span>	y:number,</span></span>
<span class="line"><span>	z:number</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let p1:point=new point2D()</span></span>
<span class="line"><span>let p2:point=new point3D()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>属性多的类型可以赋值给属性少的类型，但属性少的类型不能赋值给属性多的类型 多的属性在赋值时会被舍弃 接口和接口之间，接口与类之间都可以兼容的</p><p><strong>函数兼容性</strong> 函数之间兼容性比较复杂，需要考虑：1参数个数2参数类型3返回值类型</p><ol><li>参数个数，参数多的兼容参数少的（或者说，参数少的可以赋值给多的）</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>type F1 =（a:number）=&gt;void</span></span>
<span class="line"><span>type F2=（a:number,b:number）=&gt;void</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Let f1:F1</span></span>
<span class="line"><span>Let f2:F2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>f2=f1 //ok</span></span>
<span class="line"><span>f1 =f2 //err</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li><p>参数类型，相同位置的参数类型要相同（对于原始类型）或兼容（对于对象类型）</p></li><li><p>返回值类型，只关注返回值类型本身即可： 如果返回值类型是原始类型，此时两个类型要相同 如果返回值类型是对象类型，此时成员多的可以赋值给成员少的</p></li></ol><h2 id="交叉类型和接口继承" tabindex="-1"><a class="header-anchor" href="#交叉类型和接口继承"><span>交叉类型和接口继承</span></a></h2><p>交叉类型（&amp;）和接口继承（extends）的对比:</p><ul><li>相同点：都可以实现对象类型的组合。</li><li>不同点：两种方式实现类型组合时，对于同名属性之间，处理类型冲突的方式不同。</li></ul><p>接口继承之间如果有同名函数签名（形参列表，返回值等）不一致的情况会报错</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>interface A{</span></span>
<span class="line"><span>	fn: (value: number)=&gt; string</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>interface B extends A{</span></span>
<span class="line"><span>	fn: (value: string)=&gt;string  //err</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>交叉类型之间同名函数签名不一致会结合在一起。两个都能调用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>interfaceA{</span></span>
<span class="line"><span>	fn: (value: number)）=&gt; string</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>interfaceB{</span></span>
<span class="line"><span>	fn: (value: string)=&gt;string</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>type C = A &amp; B //ok</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="泛型工具类" tabindex="-1"><a class="header-anchor" href="#泛型工具类"><span>泛型工具类</span></a></h1><h2 id="partial" tabindex="-1"><a class="header-anchor" href="#partial"><span>Partial</span></a></h2><p>将一个类型的属性都变为可选的 构造出来的新类型原相同，但所有属性都变为可选的。</p><h2 id="readonly-1" tabindex="-1"><a class="header-anchor" href="#readonly-1"><span>Readonly</span></a></h2><p>将一个类型的属性都变为只读的 构造出来的新类型原相同，但所有属性都变为只读的。</p><h2 id="pick" tabindex="-1"><a class="header-anchor" href="#pick"><span>Pick</span></a></h2><p>pick工具类型用于挑选出一个类型中需要的字段返回出新的类型</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const user={</span></span>
<span class="line"><span>	id:666,</span></span>
<span class="line"><span>	name:&#39;阿宝哥&#39;,</span></span>
<span class="line"><span>	address: &#39;cn&#39;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>const PickedUser=Pick(user, [&quot;id&quot;, &quot;name&quot;]);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>PickedUser={</span></span>
<span class="line"><span>	id:666,</span></span>
<span class="line"><span>	name:&#39;阿宝哥&#39;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="omit" tabindex="-1"><a class="header-anchor" href="#omit"><span>Omit</span></a></h2><p>omit工具类型用于挑选出一个类型中不需要的字段返回新的类型和pick相反</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>type User = {</span></span>
<span class="line"><span>	id:string;//用户</span></span>
<span class="line"><span>	name:string;//用户名</span></span>
<span class="line"><span>	password:string;//密码</span></span>
<span class="line"><span>	createdAt:Date;//创建时间</span></span>
<span class="line"><span>	updatedAt:Date;//更新时间</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>const a=Omit&lt;User, &quot;id&quot; | &quot;createdAt&quot; | &quot;updateAt&quot;&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>a={</span></span>
<span class="line"><span>	name:string;</span></span>
<span class="line"><span>	password:string;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="record-1" tabindex="-1"><a class="header-anchor" href="#record-1"><span>Record</span></a></h2><p>简化实现统一类型的属性的对象类型</p><ul><li>第一个参数是交叉类型，其中每个字符串的值都会作为创建类型的属性字段</li><li>第二个参数是指定所有属性字段的类型</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>type Recordobj = Record&lt;&#39;a&#39; | &#39;b&#39; | &#39;c&#39;,string[]&gt;</span></span>
<span class="line"><span>//相当于</span></span>
<span class="line"><span>type Recordobj ={</span></span>
<span class="line"><span>	a:string[]</span></span>
<span class="line"><span>	b:string[]</span></span>
<span class="line"><span>	c:string[]</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="文件类型" tabindex="-1"><a class="header-anchor" href="#文件类型"><span>文件类型</span></a></h1><p>TS 中有两种文件类型：</p><ol><li>ts文件 implementation（代码实现文件） 既包含类型信息又可执行代码。 可以被编译为js文件，然后，执行代码。 用途：编写程序代码的地方。</li><li>d.ts文件 declaration（类型声明文件）。 只包含类型信息的类型声明文件。 不会生成js文件，仅用于提供类型信息。 用途：为JS提供类型信息。</li></ol><h2 id="三斜线指令" tabindex="-1"><a class="header-anchor" href="#三斜线指令"><span>三斜线指令</span></a></h2><p>三斜线指令相当于es6的import操作，都是导包</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>/// &lt;reference type=&quot;type/typescript&quot; /&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div>`,87)]))}const t=n(l,[["render",d]]),c=JSON.parse('{"path":"/front/ts/3/","title":"3 进阶","lang":"zh-CN","frontmatter":{"title":"3 进阶","createTime":"2025/04/12 21:19:02","permalink":"/front/ts/3/"},"readingTime":{"minutes":6.48,"words":1945},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/TypeScript/3 进阶.md","headers":[]}');export{t as comp,c as data};
